sb.AppendLine("Pieces: " + parts.Count);
var refs = new System.Collections.Generic.Dictionary<string, int>();
foreach (ElementId part in parts)
{
    try
    {
        DocumentId defDoc = TopSolidDesignHost.Assemblies.GetOccurrenceDefinition(part);
        if (defDoc.IsEmpty) continue;
        string name = TopSolidHost.Documents.GetName(defDoc);
        if (refs.ContainsKey(name)) refs[name]++;
        else refs[name] = 1;
    }
    catch { }
}
sb.AppendLine("References uniques: " + refs.Count);
foreach (var kv in refs)
    sb.AppendLine("  " + kv.Key + " x" + kv.Value);
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
var sketches = TopSolidHost.Sketches2D.GetSketches(docId);
if (sketches.Count == 0) return "Diagnostic: 0 esquisses (document sans esquisse).";
var sb = new System.Text.StringBuilder();
sb.AppendLine("Diagnostic esquisses (" + sketches.Count + "):");
int totalProblems = 0;
foreach (ElementId sketch in sketches)
{
    string name = TopSolidHost.Elements.GetFriendlyName(sketch);
    var profiles = TopSolidHost.Sketches2D.GetProfiles(sketch);
    if (profiles.Count == 0)
    {
        sb.AppendLine("  " + name + ": VIDE (aucun profil)");
        totalProblems++;
        continue;
    }
    foreach (var profile in profiles)
    {
        bool closed = TopSolidHost.Sketches2D.IsProfileClosed(profile);
        var segments = TopSolidHost.Sketches2D.GetProfileSegments(profile);
        if (!closed)
        {
            sb.AppendLine("  " + name + ": PROFIL OUVERT (" + segments.Count + " segments)");
            totalProblems++;
        }
        else
            sb.AppendLine("  " + name + ": OK (" + segments.Count + " segments, ferme)");
    }
}
sb.AppendLine("Problemes: " + totalProblems);
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
PdmObjectId pdmId = TopSolidHost.Documents.GetPdmObject(docId);
var sb = new System.Text.StringBuilder();
sb.AppendLine("Document: " + TopSolidHost.Pdm.GetName(pdmId));
string majorText;
string minorText;
TopSolidHost.Pdm.GetRevisionTexts(pdmId, out majorText, out minorText);
sb.AppendLine("Revision: " + majorText + "." + minorText);
try
{
    PdmMinorRevisionId finalRev = TopSolidHost.Pdm.GetFinalMinorRevision(pdmId);
    PdmMinorRevisionId currentRev = TopSolidHost.Documents.GetPdmMinorRevision(docId);
    sb.AppendLine("A jour: " + (finalRev.Id == currentRev.Id ? "OUI" : "NON — revision plus recente disponible"));
}
catch { sb.AppendLine("Info revision detaillee non disponible."); }
try { sb.AppendLine("Description: " + TopSolidHost.Pdm.GetDescription(pdmId)); } catch { }
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
var shapes = TopSolidHost.Shapes.GetShapes(docId);
if (shapes.Count == 0) return "Aucun shape — document sans geometrie.";
var sb = new System.Text.StringBuilder();
sb.AppendLine("Encombrement du document: " + TopSolidHost.Documents.GetName(docId));
double gXmin = double.MaxValue, gYmin = double.MaxValue, gZmin = double.MaxValue;
double gXmax = double.MinValue, gYmax = double.MinValue, gZmax = double.MinValue;
foreach (ElementId shape in shapes)
{
    var faces = TopSolidHost.Shapes.GetFaces(shape);
    foreach (var face in faces)
    {
        double xmin, ymin, zmin, xmax, ymax, zmax;
        TopSolidHost.Shapes.GetFaceEnclosingCoordinates(face, out xmin, out ymin, out zmin, out xmax, out ymax, out zmax);
        if (xmin < gXmin) gXmin = xmin;
        if (ymin < gYmin) gYmin = ymin;
        if (zmin < gZmin) gZmin = zmin;
        if (xmax > gXmax) gXmax = xmax;
        if (ymax > gYmax) gYmax = ymax;
        if (zmax > gZmax) gZmax = zmax;
    }
}
double dx = (gXmax - gXmin) * 1000;
double dy = (gYmax - gYmin) * 1000;
double dz = (gZmax - gZmin) * 1000;
sb.AppendLine("Dimensions hors-tout:");
sb.AppendLine("  X: " + dx.ToString("F1") + " mm");
sb.AppendLine("  Y: " + dy.ToString("F1") + " mm");
sb.AppendLine("  Z: " + dz.ToString("F1") + " mm");
double vol = dx * dy * dz / 1e9;
sb.AppendLine("Volume boite: " + vol.ToString("F4") + " m3");
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
var shapes = TopSolidHost.Shapes.GetShapes(docId);
if (shapes.Count == 0) return "Aucun shape.";
var sb = new System.Text.StringBuilder();
double minRadius = double.MaxValue;
int cylCount = 0;
foreach (ElementId shape in shapes)
{
    var faces = TopSolidHost.Shapes.GetFaces(shape);
    foreach (var face in faces)
    {
        SurfaceType st = TopSolidHost.Shapes.GetFaceSurfaceType(face);
        if (st == SurfaceType.Cylinder)
        {
            double r = TopSolidHost.Shapes.GetFaceCylinderRadius(face);
            cylCount++;
            if (r < minRadius) minRadius = r;
        }
    }
}
sb.AppendLine("Analyse usinabilite:");
sb.AppendLine("Faces cylindriques: " + cylCount);
if (cylCount > 0)
{
    sb.AppendLine("Rayon minimum: " + (minRadius * 1000).ToString("F2") + " mm");
    sb.AppendLine("Fraise max: diam " + (minRadius * 2000).ToString("F1") + " mm");
}
else
    sb.AppendLine("Aucune face cylindrique detectee.");
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
PdmObjectId pdmId = TopSolidHost.Documents.GetPdmObject(docId);
var sb = new System.Text.StringBuilder();
sb.AppendLine("Proprietes de: " + TopSolidHost.Pdm.GetName(pdmId));
var pList = TopSolidHost.Parameters.GetParameters(docId);
int userCount = 0;
foreach (ElementId p in pList)
{
    if (TopSolidHost.Elements.HasSystemName(p)) continue;
    string name = TopSolidHost.Elements.GetFriendlyName(p);
    ParameterType pt = TopSolidHost.Parameters.GetParameterType(p);
    string val = "";
    try
    {
        switch (pt)
        {
            case ParameterType.Real: val = (TopSolidHost.Parameters.GetRealValue(p) * 1000).ToString("F2") + " mm"; break;
            case ParameterType.Text: val = TopSolidHost.Parameters.GetTextValue(p); break;
            case ParameterType.Boolean: val = TopSolidHost.Parameters.GetBooleanValue(p).ToString(); break;
            case ParameterType.Integer: val = TopSolidHost.Parameters.GetIntegerValue(p).ToString(); break;
            default: val = "(" + pt + ")"; break;
        }
    }
    catch { val = "?"; }
    sb.AppendLine("  " + name + " = " + val);
    userCount++;
}
sb.AppendLine("Total attributs utilisateur: " + userCount);
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
var sb = new System.Text.StringBuilder();
var shapes = TopSolidHost.Shapes.GetShapes(docId);
if (shapes.Count == 0) return "Aucun shape dans le document.";
var volumes = new System.Collections.Generic.List<KeyValuePair<string, double>>();
foreach (ElementId s in shapes)
{
    string name = TopSolidHost.Elements.GetFriendlyName(s);
    try
    {
        double vol = TopSolidHost.Shapes.GetShapeVolume(s);
        volumes.Add(new KeyValuePair<string, double>(name, vol));
    }
    catch { }
}
volumes.Sort(delegate(KeyValuePair<string, double> a, KeyValuePair<string, double> b) { return b.Value.CompareTo(a.Value); });
sb.AppendLine("Top shapes par volume:");
double totalVol = 0;
foreach (var kv in volumes) totalVol += kv.Value;
int top = volumes.Count > 5 ? 5 : volumes.Count;
for (int i = 0; i < top; i++)
{
    double pct = totalVol > 0 ? (volumes[i].Value / totalVol * 100) : 0;
    sb.AppendLine("  " + (i+1) + ". " + volumes[i].Key + ": " + (volumes[i].Value * 1e9).ToString("F1") + " cm3 (" + pct.ToString("F0") + "%)");
}
sb.AppendLine("Volume total: " + (totalVol * 1e9).ToString("F1") + " cm3");
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
var sb = new System.Text.StringBuilder();
sb.AppendLine("Audit standardisation:");
var projectId = TopSolidHost.Pdm.GetCurrentProject();
List<PdmObjectId> folders;
List<PdmObjectId> files;
TopSolidHost.Pdm.GetConstituents(projectId, out folders, out files);
int fromLib = 0;
int local = 0;
foreach (PdmObjectId f in files)
{
    DocumentId d = TopSolidHost.Documents.GetDocument(f);
    if (d.IsEmpty) continue;
    if (TopSolidHost.Families.IsFamily(d))
        fromLib++;
    else
        local++;
}
sb.AppendLine("  Familles (bibliotheque): " + fromLib);
sb.AppendLine("  Documents locaux: " + local);
if (local > 0 && fromLib > 0)
    sb.AppendLine("Ratio standard: " + (fromLib * 100 / (fromLib + local)) + "%");
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
var shapes = TopSolidHost.Shapes.GetShapes(docId);
var sb = new System.Text.StringBuilder();
sb.AppendLine("Audit performance CAO:");
int totalFaces = 0;
int totalEdges = 0;
foreach (ElementId s in shapes)
{
    string name = TopSolidHost.Elements.GetFriendlyName(s);
    int fc = TopSolidHost.Shapes.GetFaceCount(s);
    int ec = TopSolidHost.Shapes.GetEdgeCount(s);
    totalFaces += fc;
    totalEdges += ec;
    sb.AppendLine("  " + name + ": " + fc + " faces, " + ec + " aretes");
}
sb.AppendLine("Total: " + totalFaces + " faces, " + totalEdges + " aretes");
if (totalFaces > 5000)
    sb.AppendLine("ATTENTION: Modele lourd (>5000 faces). Envisager representation simplifiee.");
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "FAIL: Aucun document ouvert.";
PdmObjectId pdmId = TopSolidHost.Documents.GetPdmObject(docId);
var sb = new System.Text.StringBuilder();
sb.AppendLine("Bilan de sante: " + TopSolidHost.Pdm.GetName(pdmId));
int warnings = 0;

// Check materiau
try
{
    DocumentId matDoc = TopSolidDesignHost.Parts.GetMaterial(docId);
    if (matDoc.IsEmpty)
    {
        sb.AppendLine("  AVERT: Aucun materiau affecte");
        warnings++;
    }
    else
        sb.AppendLine("  OK: Materiau = " + TopSolidHost.Documents.GetName(matDoc));
}
catch { sb.AppendLine("  INFO: Verification materiau non applicable"); }

// Check parametres
var pList = TopSolidHost.Parameters.GetParameters(docId);
int userParams = 0;
foreach (ElementId p in pList)
{
    if (!TopSolidHost.Elements.HasSystemName(p)) userParams++;
}
sb.AppendLine("  OK: " + userParams + " parametres utilisateur");

// Check revision
try
{
    string major;
    string minor;
    TopSolidHost.Pdm.GetRevisionTexts(pdmId, out major, out minor);
    sb.AppendLine("  OK: Revision " + major + "." + minor);
}
catch { }

// Check geometrie
var shapes = TopSolidHost.Shapes.GetShapes(docId);
if (shapes.Count == 0)
{
    sb.AppendLine("  AVERT: Aucune geometrie");
    warnings++;
}
else
    sb.AppendLine("  OK: " + shapes.Count + " shape(s)");

// Check esquisses
var sketches = TopSolidHost.Sketches2D.GetSketches(docId);
int openProfiles = 0;
foreach (ElementId sk in sketches)
{
    var profiles = TopSolidHost.Sketches2D.GetProfiles(sk);
    foreach (var pf in profiles)
    {
        if (!TopSolidHost.Sketches2D.IsProfileClosed(pf)) openProfiles++;
    }
}
if (openProfiles > 0)
{
    sb.AppendLine("  AVERT: " + openProfiles + " profil(s) ouvert(s)");
    warnings++;
}

sb.AppendLine("Resultat: " + (warnings == 0 ? "OK" : warnings + " avertissement(s)"));
return sb.ToString();

DocumentId docId = TopSolidHost.Documents.EditedDocument;
